import axios from 'axios';
import { IPFS_CONFIG } from './config';

// Upload file to IPFS via Pinata
export async function uploadToIPFS(file) {
  try {
    const formData = new FormData();
    formData.append('file', file);

    const response = await axios.post(
      'https://api.pinata.cloud/pinning/pinFileToIPFS',
      formData,
      {
        headers: {
          'Content-Type': 'multipart/form-data',
          pinata_api_key: IPFS_CONFIG.pinataApiKey,
          pinata_secret_api_key: IPFS_CONFIG.pinataSecret,
        },
        maxContentLength: Infinity,
        maxBodyLength: Infinity,
      }
    );

    return {
      success: true,
      ipfsHash: response.data.IpfsHash,
      pinSize: response.data.PinSize,
      timestamp: response.data.Timestamp,
    };
  } catch (error) {
    console.error('Error uploading to IPFS:', error);
    return {
      success: false,
      error: error.response?.data?.error || error.message,
    };
  }
}

// Upload JSON metadata to IPFS
export async function uploadMetadataToIPFS(metadata) {
  try {
    const response = await axios.post(
      'https://api.pinata.cloud/pinning/pinJSONToIPFS',
      {
        pinataContent: metadata,
        pinataMetadata: {
          name: `${metadata.name} - NFT Metadata`,
          keyvalues: {
            type: 'nft-metadata',
            creator: metadata.creator || 'unknown',
          },
        },
      },
      {
        headers: {
          'Content-Type': 'application/json',
          pinata_api_key: IPFS_CONFIG.pinataApiKey,
          pinata_secret_api_key: IPFS_CONFIG.pinataSecret,
        },
      }
    );

    return {
      success: true,
      ipfsHash: response.data.IpfsHash,
      pinSize: response.data.PinSize,
      timestamp: response.data.Timestamp,
    };
  } catch (error) {
    console.error('Error uploading metadata to IPFS:', error);
    return {
      success: false,
      error: error.response?.data?.error || error.message,
    };
  }
}

// Get IPFS gateway URL
export function getIPFSUrl(ipfsHash) {
  return `${IPFS_CONFIG.gateway}${ipfsHash}`;
}

// Create complete NFT metadata
export function createNFTMetadata(name, description, mediaUrl, mediaType, attributes = []) {
  const metadata = {
    name: name,
    description: description,
    attributes: [
      {
        trait_type: 'Media Type',
        value: mediaType,
      },
      ...attributes,
    ],
    created_at: new Date().toISOString(),
  };

  // Add media URL based on type
  if (mediaType === 'image') {
    metadata.image = mediaUrl;
  } else if (mediaType === 'audio') {
    metadata.audio = mediaUrl;
    metadata.image = 'https://ipfs.io/ipfs/QmXZxLkNvxhZq8x6kFbLpVEXJb4vK6NqZ3kF7a9qL3q9mN/audio-placeholder.png'; // Placeholder image for audio NFTs
  } else if (mediaType === 'video') {
    metadata.video = mediaUrl;
    metadata.image = 'https://ipfs.io/ipfs/QmXZxLkNvxhZq8x6kFbLpVEXJb4vK6NqZ3kF7a9qL3q9mN/video-placeholder.png'; // Placeholder image for video NFTs
  }

  return metadata;
}

// Alternative IPFS client using Infura (fallback)
export async function uploadToInfuraIPFS(file) {
  try {
    const formData = new FormData();
    formData.append('file', file);

    const response = await axios.post(
      'https://ipfs.infura.io:5001/api/v0/add',
      formData,
      {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
        auth: {
          username: process.env.REACT_APP_INFURA_IPFS_PROJECT_ID,
          password: process.env.REACT_APP_INFURA_IPFS_PROJECT_SECRET,
        },
      }
    );

    return {
      success: true,
      ipfsHash: response.data.Hash,
    };
  } catch (error) {
    console.error('Error uploading to Infura IPFS:', error);
    return {
      success: false,
      error: error.message,
    };
  }
}

// Check if IPFS is available
export async function checkIPFSAvailability() {
  try {
    // Check if we have the required API keys
    if (!IPFS_CONFIG.pinataApiKey || !IPFS_CONFIG.pinataSecret) {
      console.warn('Pinata API keys not found in environment variables');
      return false;
    }

    // Test Pinata API
    const response = await axios.get(
      'https://api.pinata.cloud/data/testAuthentication',
      {
        headers: {
          pinata_api_key: IPFS_CONFIG.pinataApiKey,
          pinata_secret_api_key: IPFS_CONFIG.pinataSecret,
        },
      }
    );

    return response.status === 200;
  } catch (error) {
    console.error('IPFS availability check failed:', error);
    return false;
  }
}
